/**
 * Stub types for library build
 * These will be generated by consumers in their projects
 */

export type IconCategory = string
export type IconName = string

export interface IconMetadata {
  name: IconName
  category: IconCategory
  viewBox: string
  width: number
  height: number
  hasMultipleColors: boolean
  colorCount: number
}

// Empty metadata - consumers will generate their own
export const ICON_METADATA: Record<IconName, IconMetadata> = {}
export const ICON_NAMES: readonly IconName[] = []
export const ICON_CATEGORIES: Record<IconCategory, readonly IconName[]> = {}
